import{_ as t,c as a,o as s,a5 as r}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse('{"title":"PostgREST — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"PostgREST 14.14 in the July 2026 PostgreSQL REST API benchmark: a complete REST API from 12 lines of configuration, a fixed connection-pool handicap, and honest last places.","frontmatter":{"layout":"doc","outline":[2,3],"title":"PostgREST — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"PostgREST 14.14 in the July 2026 PostgreSQL REST API benchmark: a complete REST API from 12 lines of configuration, a fixed connection-pool handicap, and honest last places.","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/postgrest.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/postgrest.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"PostgREST — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"property":"og:description","content":"PostgREST 14.14 in the July 2026 PostgreSQL REST API benchmark: a complete REST API from 12 lines of configuration, a fixed connection-pool handicap, and honest last places."}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"PostgREST — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"name":"twitter:description","content":"PostgREST 14.14 in the July 2026 PostgreSQL REST API benchmark: a complete REST API from 12 lines of configuration, a fixed connection-pool handicap, and honest last places."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"blog/benchmarks-2026-07/postgrest.md","filePath":"blog/benchmarks-2026-07/postgrest.md","lastUpdated":1782480183000}'),n={name:"blog/benchmarks-2026-07/postgrest.md"};function i(o,e,l,h,d,p){return s(),a("div",null,e[0]||(e[0]=[r(`<h1 id="postgrest-14-14" tabindex="-1">PostgREST 14.14 <a class="header-anchor" href="#postgrest-14-14" aria-label="Permalink to &quot;PostgREST 14.14&quot;">​</a></h1><p class="blog-meta"><span class="tag">Benchmark</span> · <span class="tag">Database-first</span> · <span class="tag">July 2026</span></p><p>Part of the <a href="/blog/benchmarks-2026-07/">PostgreSQL REST API Benchmark, July 2026</a> series.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Version</strong></td><td>PostgREST 14.14 (Haskell / GHC runtime)</td></tr><tr><td><strong>PostgreSQL driver</strong></td><td>Built-in pool — <code>db-pool = 100</code> (the default is 10)</td></tr><tr><td><strong>Concurrency model</strong></td><td>GHC green threads — no configuration</td></tr><tr><td><strong>Lines of code</strong></td><td><strong>12 (config only)</strong> — the lowest in the benchmark</td></tr><tr><td><strong>Podiums</strong></td><td>none — 0 of 38 combinations</td></tr><tr><td><strong>Source</strong></td><td><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/postgrest-v14.14" target="_blank" rel="noreferrer">postgrest-v14.14</a></td></tr></tbody></table></div></div><p><strong>The verdict in one sentence: twelve lines of configuration buy a complete REST API that keeps pace wherever the database does the work — and trails the field everywhere the server does.</strong></p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>There is no application. The entire service is <a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/postgrest-v14.14/postgrest.conf" target="_blank" rel="noreferrer">postgrest.conf</a>; functions are called as <code>/rpc/perf_test?_records=...</code> instead of the <code>/api/perf-test</code> style the coded services use:</p><details class="code-collapsible" open><summary>ini</summary><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">db-uri</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">       =</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;postgres://testuser:testpass@postgres:5432/testdb&quot;</span></span>
<span class="line"><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">db-schema</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">    =</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;public&quot;</span></span>
<span class="line"><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">db-anon-role</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> =</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;testuser&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;"># Match the 100-connection pool every other service uses (default is only 10)</span></span>
<span class="line"><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">db-pool</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> =</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> 100</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">log-level</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> =</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;crit&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></details><p>The <code>db-pool</code> line is this round&#39;s fix: in January PostgREST ran its default of 10 connections while the field had ~100 — a silent 10× handicap on the resource every scenario contends for.</p><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><h3 id="where-config-only-holds-up" tabindex="-1">Where config-only holds up <a class="header-anchor" href="#where-config-only-holds-up" aria-label="Permalink to &quot;Where config-only holds up&quot;">​</a></h3><p>On the heaviest payloads, where connection availability and database time dominate, PostgREST sits in the top third of the field:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>perf-test</th><th style="text-align:right;">100 records</th><th style="text-align:right;">500 records</th></tr></thead><tbody><tr><td>50 VU</td><td style="text-align:right;">169 (#7)</td><td style="text-align:right;">35 (#8)</td></tr><tr><td>100 VU</td><td style="text-align:right;">168 (#6)</td><td style="text-align:right;">35 (#6)</td></tr><tr><td>200 VU</td><td style="text-align:right;">168 (#6)</td><td style="text-align:right;">35 (#5)</td></tr></tbody></table></div></div><p>At 200 VU/500 records its #5 places it ahead of both Rust frameworks and all four JavaScript runtimes — proof that with a full-size pool, the Haskell runtime moves heavy rows as well as most hand-written services.</p><h3 id="where-it-trails" tabindex="-1">Where it trails <a class="header-anchor" href="#where-it-trails" aria-label="Permalink to &quot;Where it trails&quot;">​</a></h3><p>Everywhere the request itself is the work, PostgREST is #19 or #20 of 20:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Scenario</th><th>Result</th></tr></thead><tbody><tr><td>perf-test, 1 record</td><td>1,363 req/s at 50 VU falling to 1,237 at 200 VU (#20 at every concurrent level)</td></tr><tr><td>Minimal baseline</td><td>6,986 req/s at 100 VU (#19) — only Django below it</td></tr><tr><td>Many parameters</td><td>3,726 req/s at 50 VU (#19) — each <code>_pN</code> becomes a parsed, type-checked function argument</td></tr><tr><td>Large payload</td><td>729 req/s at 25 VU/100 KB and 164 at 25 VU/500 KB (#20 in all four combos) — roughly half of the #19 result</td></tr></tbody></table></div></div><p>Large payloads are the sore spot: the field clusters at 1,287–1,427 req/s on the 100 KB combos; PostgREST manages 727–729.</p><h3 id="latency" tabindex="-1">Latency <a class="header-anchor" href="#latency" aria-label="Permalink to &quot;Latency&quot;">​</a></h3><p>The 1-record tails tell the same story as the throughput table: p99 of 151 ms at 50 VU, 342 ms at 100 VU, and 755 ms at 200 VU — an order of magnitude above the leaders&#39; 25–48 ms band at 50 VU. It was also the only service to break 1 s p99 on a large-payload combination (1,189 ms at 50 VU/500 KB). On the heavy perf-test combos, where it ranks well, its tails match the pack (2,515 ms at 200 VU/100 rec, mid-field).</p><h2 id="resource-usage" tabindex="-1">Resource usage <a class="header-anchor" href="#resource-usage" aria-label="Permalink to &quot;Resource usage&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:right;">Peak memory</th><th style="text-align:right;">Avg memory</th><th style="text-align:right;">Avg CPU</th></tr></thead><tbody><tr><td style="text-align:right;">112 MB</td><td style="text-align:right;">57 MB</td><td style="text-align:right;">103.0%</td></tr></tbody></table></div></div><p>Third-smallest peak footprint of all 20 services, behind only Swoole (44 MB) and Go (59 MB). A complete REST layer in 57 MB average is a respectable bill for zero application code.</p><h2 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h2><p>PostgREST&#39;s value is density, not speed. Twelve lines of configuration — the <a href="/blog/benchmarks-2026-07/analysis.html#performance-per-line-of-code">lines-of-code winner</a> by a wide margin — produce six working endpoints plus a full REST surface (filtering, embedding, JWT auth) this benchmark never exercises. Every coded service on these pages spends 100–300 lines to match what one config file does. The trade is a fixed per-request tax that no configuration removes: last place in every small-request category, at every concurrency level.</p><p>But the tax is not inherent to the <em>approach</em>. <a href="/blog/benchmarks-2026-07/npgsqlrest.html">NpgsqlRest</a>, the other config-only competitor (21 lines), serves the same database-first idea at 15,549 req/s on the minimal baseline where PostgREST posts 6,986, and 2,615 req/s on 1-record perf-test where PostgREST posts 1,322 — roughly 2× on both, from a config file of comparable size. Database-first is not the bottleneck; this particular request pipeline is.</p><p><strong>January → July movement:</strong> the <code>db-pool</code> 10 → 100 fix is the headline change, and its signature is visible in the heavy combinations, where PostgREST now holds #5–#8 instead of queueing on a starved pool; the small-request categories stayed at the bottom, as in January. Rankings only — the methodology changed too much for absolute comparisons.</p><h2 id="explore-on-github" tabindex="-1">Explore on GitHub <a class="header-anchor" href="#explore-on-github" aria-label="Permalink to &quot;Explore on GitHub&quot;">​</a></h2><p>Everything this page claims can be checked against the running code and the raw output:</p><ul><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/postgrest-v14.14" target="_blank" rel="noreferrer">Configuration</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_postgres/init.sql" target="_blank" rel="noreferrer">The PostgreSQL functions every service calls</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/scripts" target="_blank" rel="noreferrer">k6 load scripts</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/results/202607131327" target="_blank" rel="noreferrer">This run&#39;s per-test k6 summaries</a> — filter by this service&#39;s name</li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_k6/results/202607131327/results.csv" target="_blank" rel="noreferrer">Complete dataset: results.csv</a></li></ul><hr><p><strong>Series:</strong> <a href="/blog/benchmarks-2026-07/">Introduction</a> · <a href="/blog/benchmarks-2026-07/analysis.html">Overall Analysis</a> · <a href="/blog/benchmarks-2026-07/results.html">Raw Results</a></p><p><strong>Next:</strong> <a href="/blog/benchmarks-2026-07/npgsqlrest.html">NpgsqlRest Deep Dive →</a></p>`,34)]))}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
